mapper.select:
SELECT * FROM ( SELECT a.*, ROWNUM rn FROM ( SELECT , DECODE(u.status, 'A', 'Active', 'I', 'Inactive', 'P', 'Pending', 'Unknown') AS status_text, NVL(d.dept_name, 'No Dept') AS dept_name, (SELECT LISTAGG(r.role_name, ', ') WITHIN GROUP (ORDER BY r.role_name) FROM user_roles ur, roles r WHERE ur.user_id = u.id AND ur.role_id = r.id(+)) AS role_names, (SELECT COUNT(*) FROM audit_log al WHERE al.user_id = u.id AND al.log_date >= ADD_MONTHS(SYSDATE, -6)) AS recent_actions FROM users u, departments d WHERE u.dept_id = d.id(+)
AND u.org_id IN ( SELECT org_id FROM org_tree START WITH org_id = #{orgId} CONNECT BY NOCYCLE PRIOR org_id = parent_id )
AND REGEXP_LIKE(u.name, #{name}, 'i')
AND u.status = #{status}
AND u.status IN ('A', 'P')
AND u.id IN ( SELECT ur.user_id FROM user_roles ur WHERE ur.role_id IN
#{roleId}
)
ORDER BY u.name ORDER BY u.created_at DESC ORDER BY u.id
) a WHERE ROWNUM <= #{pageEnd} ) WHERE rn > #{pageStart}
